#include <iostream>
using namespace std;
typedef long long ll;
ll powermod(ll b,ll p,ll k)
{
    ll ans=1;
    b=b%k;
    while(p>0)
    {
        if(p%2==1)
        {
            ans=(ans%k*b%k)%k;
        }
        p=p/2;
        b=(b%k*b%k)%k;
    }
    return ans;
}
int main()
{
    ll b,p,k;
    cin>>b>>p>>k;
    cout<<b<<'^'<<p<<" mod "<<k<<'='<<powermod(b,p,k);
    return 0;
}
